package programming;

public class Swapping {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a = 70;
		int b = 35;
		System.out.println("Before swapping a = " + a + " and b = " + b );
		 a = a + b;
		 b = a - b;
		 a = a - b;
		 System.out.println("After swapping a = " + a + " and b = " + b);

	}

}
